class Solution:
    def clumsy(self, n: int) -> int:
        stack = [n]
        n -= 1
        index = 0
        while n > 0:
            if index % 4 == 0:
                num = stack.pop()
                stack.append(num * n)
            elif index % 4 == 1:
                num = stack.pop()
                stack.append(num // n)
            elif index % 4 == 2:
                stack.append(n)
            else:
                num = stack.pop()
                stack.append(num - n)
            n -= 1
            index += 1
        return stack[0]

